#nullable enable // autogenerated

using System;
using System.Collections.Generic;
using System.Linq;
using MVZ2.Level;
using MVZ2.Managers;
using MVZ2.Models;
using MVZ2.UI.Level;
using MVZ2.Vanilla.Grids;
using MVZ2Logic.Entities;
using MVZ2Logic.Games;
using MVZ2Logic.Grids;
using MVZ2Logic.HeldItems;
using MVZ2Logic.Inputs;
using MVZ2Logic.Options;
using PVZEngine.Buffs;
using PVZEngine.Entities;
using PVZEngine.Grids;
using PVZEngine.Level;
using PVZEngine.Definitions;
using UnityEngine;
using UnityEngine.EventSystems;

namespace MVZ2.Grids
{
    public class GridController : MonoBehaviour, ILevelRaycastReceiver
    {
        #region 生命周期
        private void Awake()
        {
            view.OnPointerInteraction += (view, pointer, interaction) => OnPointerInteraction?.Invoke(this, pointer, interaction);
            hpBarSource = new GridHPBarSource(this);
        }
        public void Init(GridInitData data)
        {
            Level = data.levelController;
            grid = data.grid;
            view.BuildModel(data.modelBuilder);

            grid.OnModelInsertionAdded += OnModelInsertionAddedCallback;
            grid.OnModelInsertionRemoved += OnModelInsertionRemovedCallback;
            UpdateModelInsertions();

            Level.AddHPBarSource(hpBarSource);
        }
        public LawnGrid? GetLawnGrid()
        {
            return grid;
        }
        public void UpdateFixed()
        {
            view.UpdateFixed();
        }
        public void UpdateFrame(float deltaTime)
        {
            view.UpdateFrame(deltaTime);

            if (grid != null)
            {
                view.SetModelSortingLayerAndOrder(grid.GetSortingLayer() ?? string.Empty, grid.GetSortingOrder());
            }
        }
        #endregion

        #region 显示
        public void UpdateGridController(GridControllerData data)
        {
            view.SetPosition(data.position);
            view.SetSprite(data.sprite);
            SetBevel(data.slope);
            SetDisplaySection(0, 1);
        }
        #endregion

        #region 设置属性
        public void SetColor(Color color)
        {
            view.SetColor(color);
        }
        public void SetDisplaySection(float start, float end)
        {
            view.SetDisplaySection(start, end, size, BevelHeight);
        }
        public void SetBevel(float height)
        {
            view.SetColliderBevel(size, height);
            BevelHeight = height;
        }
        #endregion

        #region 坐标转换
        public Vector2 TransformWorld2ColliderPosition(Vector3 worldPosition)
        {
            var pos2D = (Vector2)transform.position;
            var lossyScale = (Vector2)transform.lossyScale;
            var lossySize = Vector2.Scale(size, lossyScale);
            var slope = BevelHeight / size.x;

            var origin = pos2D - lossySize * 0.5f;
            var relativeWorldPos = (Vector2)worldPosition - origin;
            var colliderX = relativeWorldPos.x / lossySize.x;

            var yOffset = slope * relativeWorldPos.x;
            var colliderY = (relativeWorldPos.y + yOffset) / lossySize.y;

            return new Vector2(colliderX, colliderY);
        }
        #endregion

        #region 模型
        public Model? GetModel()
        {
            return view.GetModel();
        }
        private void UpdateModelInsertions()
        {
            if (grid != null)
                view.UpdateModelInsertions(grid.GetModelInsertions());
        }
        private void OnModelInsertionAddedCallback(ModelInsertion insertion)
        {
            var model = GetModel();
            if (model.Exists())
                model.AddModelInsertion(insertion);
        }
        private void OnModelInsertionRemovedCallback(ModelInsertion insertion)
        {
            var model = GetModel();
            if (model.Exists())
                model.RemoveModelInsertion(insertion.key);
        }
        #endregion

        #region ILevelRaycasterReceiver接口实现
        bool ILevelRaycastReceiver.IsValidReceiver(LevelEngine level, HeldItemDefinition definition, IHeldItemData data, PointerEventData eventData)
        {
            if (definition == null)
                return false;
            var grid = level.GetGrid(Column, Lane);
            if (grid == null)
                return false;
            var target = new HeldItemTargetGrid(grid, TransformWorld2ColliderPosition(eventData.pointerCurrentRaycast.worldPosition));
            var pointer = InputHelper.GetPointerDataFromEventData(eventData);
            return definition.IsValidFor(target, data, pointer);
        }
        int ILevelRaycastReceiver.GetSortingLayer()
        {
            return view.GetSortingLayerID();
        }
        int ILevelRaycastReceiver.GetSortingOrder()
        {
            return view.GetSortingOrder();
        }
        #endregion

        #region 序列化
        public SerializableGridController ToSerializable()
        {
            var model = GetModel();
            return new SerializableGridController()
            {
                model = model?.ToSerializable()
            };
        }
        public void LoadFromSerializable(SerializableGridController seri)
        {
            var model = GetModel();
            if (seri.model != null && model.Exists())
            {
                model.LoadFromSerializable(seri.model);
                model.UpdateFrame(0);
                UpdateModelInsertions();
            }
        }
        #endregion


        public event Action<GridController, PointerEventData, PointerInteraction>? OnPointerInteraction;

        public MainManager Main => MainManager.Instance;
        public LevelController? Level { get; private set; }
        public int Lane { get; set; }
        public int Column { get; set; }
        public float BevelHeight { get; private set; }
        private LawnGrid? grid;
        private IHPBarSource hpBarSource = null!;
        [SerializeField]
        private GridView view = null!;
        [SerializeField]
        private Vector2 size;
    }
    public struct GridInitData
    {
        public LevelController levelController;
        public LawnGrid grid;
        public ModelBuilder modelBuilder;
    }
    public struct GridControllerData
    {
        public Vector3 position;
        public Sprite? sprite;
        public float slope;
    }
    public class SerializableGridController
    {
        public SerializableModelData? model;
    }

    public class GridHPBarSource : IHPBarSource
    {
        public GridHPBarSource(GridController controller)
        {
            Controller = controller;
        }

        public bool IsActive()
        {
            if (!Controller.Exists())
                return false;
            if (Controller.Level == null)
                return false;
            if (Controller.GetLawnGrid() == null)
                return false;
            return true;
        }
        public Vector3 GetPosition()
        {
            return Controller.transform.position;
        }
        public void UpdateHPBarList(HPBarList list)
        {
            list.gameObject.name = Controller.gameObject.name;

            gridHPBarEntityBuffer.Clear();
            gridHPBarBuffer.Clear();
            GetHPBarViewDatas();

            list.SetBarCount(gridHPBarBuffer.Count);
            for (int i = 0; i < gridHPBarBuffer.Count; i++)
            {
                list.UpdateBar(i, gridHPBarBuffer[i]);
            }
        }
        private void GetHPBarViewDatas()
        {
            var level = Controller.Level;
            var grid = Controller.GetLawnGrid();
            if (grid == null)
                return;

            var amountMode = Main.OptionsManager.GetHPBarAmountMode();

            bool shouldShow = level?.ShouldShowHPBars() ?? false;
            var layers = grid.GetLayers().OrderBy(l => Array.IndexOf(VanillaGridLayers.normalLayerOrders, l));
            foreach (var layer in layers)
            {
                var layerDefinition = Main.Game.GetGridLayerDefinition(layer);
                var entities = grid.GetLayerEntities(layer);
                foreach (var entity in entities)
                {
                    if (!entity.Exists())
                        continue;
                    var visibility = entity.GetHPBarVisibility();
                    if (visibility == HPBarVisibility.HIDDEN)
                        continue;
                    if (!shouldShow && visibility != HPBarVisibility.FORCE)
                        continue;
                    if (entity.GetGrid() != grid)
                        continue;
                    if (gridHPBarEntityBuffer.Contains(entity))
                        continue;
                    var entityCtrl = level?.GetEntityController(entity);
                    if (!entityCtrl.Exists() || !entityCtrl.ShouldShowMainHPBar() || entityCtrl.ShouldShowHPBarOnEntity())
                        continue;
                    var barColor = layerDefinition?.HPBarColor ?? Color.red;
                    var amount = entityCtrl.GetMainHPBarAmount();
                    var text = entityCtrl.GetMainHPBarText(amountMode);
                    Sprite? icon = Main.GetFinalSprite(layerDefinition?.HPBarIcon);
                    gridHPBarBuffer.Add(new HPBarViewData()
                    {
                        barColor = barColor,
                        barAmount = amount,
                        text = text,
                        icon = icon
                    });
                    gridHPBarEntityBuffer.Add(entity);
                }
            }
        }
        public MainManager Main => MainManager.Instance;
        public GridController Controller { get; }
        private HashSet<Entity> gridHPBarEntityBuffer = new HashSet<Entity>();
        private List<HPBarViewData> gridHPBarBuffer = new List<HPBarViewData>();
    }
}
